// Make sure choices exist
if (!$json.choices || $json.choices.length === 0) {
  throw new Error('No choices found in AI output');
}

// Get the full email text
const fullText = $json.choices[0].message.content;
if (!fullText) {
  throw new Error('Content is empty');
}

// remove em dashes and common dash replacements
const cleanedText = fullText
  .replace(/—/g, ',')    // em dash → comma
  .replace(/--/g, ',')   // double hyphen → comma
  .replace(/ - /g, ', '); // space-hyphen-space → comma + space

// Extract SHORT_REF and CORE_ACTIVITY from cleaned text
const shortRefMatch = cleanedText.match(/SHORT_REF:\s*(.+)/);
const coreActivityMatch = cleanedText.match(/CORE_ACTIVITY:\s*(.+)/);
const shortRef = shortRefMatch ? shortRefMatch[1].trim() : "";
const coreActivity = coreActivityMatch ? coreActivityMatch[1].trim() : "";

// Remove SHORT_REF and CORE_ACTIVITY from email body
const emailBody = cleanedText
  .replace(/SHORT_REF:.+/s, "")
  .replace(/CORE_ACTIVITY:.+/s, "")
  .trim();

// Get lead info from loop
const firstName = $('Loop Over Items').item.json.first_name;
const lastName = $('Loop Over Items').item.json.last_name;
const email = $('Loop Over Items').item.json.email;

// Check if email exists
if (!email || email.trim() === '') {
  throw new Error(`Email of ${firstName} ${lastName} is not found, please delete it from the file then upload it again`);
}

const lead = $('Qwen Ai').item.json;

return {
  email: email,
  first_name: firstName,
  last_name: lastName,
  company_name: $('Loop Over Items').item.json.company,
  location: $('Loop Over Items').item.json.country,
  personalization: emailBody,
  custom_variables_short_ref: shortRef,
  custom_variables_core_activity: coreActivity,
  custom_variables_location: lead.country,
  email_body: emailBody
};

const csvText = $json.data;
const lines = csvText.split('\r\n').filter(line => line.trim() !== '');
const headers = lines[0].split(',');

function parseCSVLine(line) {
  const values = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      values.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  values.push(current.trim());
  return values;
}

const results = [];
for (let i = 1; i < lines.length; i++) {
  const values = parseCSVLine(lines[i]);
  const row = {};
  headers.forEach((header, index) => {
    row[header.trim()] = values[index] || '';
  });
  results.push({
    json: {
      first_name: row['First Name'],
      last_name: row['Last Name'],
      title: row['Title'],
      company: row['Company Name'],
      email: row['Email'],
      industry: row['Industry'],
      country: row['Country'],
      keywords: row['Keywords']
    }
  });
}

return results;
